    lo, hi = 0, len(arr) - 1
    trace = []
    while lo <= hi:
        mid = (lo + hi) // 2
        trace.append(mid)
        if arr[mid] == target:
            return trace
        if arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return trace

